$patients=$st->fetchAll(); $stats=['patients'=>$pdo->query('SELECT COUNT(*) FROM patients')->fetchColumn(),'visits'=>$pdo->query('SELECT COUNT(*) FROM visits')->fetchColumn(),'high'=>$pdo->query("SELECT COUNT(*) FROM ai_risk_assessments a JOIN (SELECT patient_id,MAX(id) mid FROM ai_risk_assessments GROUP BY patient_id) x ON x.mid=a.id WHERE a.level='High'")->fetchColumn(),'icu'=>$pdo->query('SELECT COUNT(*) FROM ventilator_cases')->fetchColumn()];
app_header('Doctor Dashboard','doctor','dashboard'); ?>
